// 本日追加された高スコアデザインを抽出
const index = JSON.parse($input.first().json.data);
const entries = Object.entries(index.entries || {});
const today = new Date().toISOString().split('T')[0];

const highScore = entries
  .filter(([id, e]) => {
    const isToday = (e.discovered_at || '').startsWith(today);
    const isHigh = (e.design_score || 0) >= 85;
    return isToday && isHigh;
  })
  .map(([id, e]) => ({
    id,
    url: e.url,
    domain: e.domain,
    aesthetic: e.aesthetic,
    score: e.design_score,
    tags: (e.tags || []).join(', '),
  }))
  .sort((a, b) => b.score - a.score)
  .slice(0, 3); // TOP3のみ

if (highScore.length === 0) {
  return [{ json: { skip: true } }];
}

return highScore.map(e => ({ json: e }));

// Claude レスポンスからHTMLを抽出して保存
const response = $input.first().json;
let html = '';

if (response.content) {
  const textBlock = response.content.find(b => b.type === 'text');
  if (textBlock) {
    html = textBlock.text.replace(/```html\s*/g, '').replace(/```/g, '').trim();
  }
}

const date = new Date().toISOString().split('T')[0].replace(/-/g, '');
const refDomain = $('高スコア抽出 (≥85)').item.json.domain || 'unknown';
const filename = `lp_${refDomain}_${date}.html`;

return [{
  json: {
    html,
    filename,
    ref_url: $('高スコア抽出 (≥85)').item.json.url,
    ref_score: $('高スコア抽出 (≥85)').item.json.score,
    ref_aesthetic: $('高スコア抽出 (≥85)').item.json.aesthetic,
  }
}];
